it("should keep a block (2x2) unchanged as a still life", () => {
  const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
  expect(result).toHaveLength(4);
  expect(result).toEqual(expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]));
});
